#include<bits/stdc++.h>
using namespace std;
long long n,ans,maxans;
int main(){
    int t;
    cin>>t;
    while(t--){
    cin>>n;
        ans=0;
        maxans=0;
    for(;n>0;){

        ans++;
        if(n%2!=1) ans=0;
        n/=2;
        maxans=max(ans,maxans);
    }
    cout<<maxans<<"\n";}

}
